import React from 'react';
import '@/styles/ui/navbar.css';

// ─────────────────────────────────────────────────────────────
//  TYPES
// ─────────────────────────────────────────────────────────────

export type NavbarVariant   = 'default' | 'bordered' | 'filled' | 'floating' | 'transparent';
export type NavbarColor     = 'white' | 'dark' | 'primary' | 'blur';
export type NavbarSize      = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
export type NavbarPosition  = 'static' | 'sticky' | 'fixed';

export interface NavItem {
  /** Unique key / href */
  key: string;

  /** Label shown in the nav link */
  label: React.ReactNode;

  /** Optional icon before the label */
  icon?: React.ReactNode;

  /** Badge count / text */
  badge?: string | number;

  /** Mark this item as the active route */
  active?: boolean;

  /** Disable this link */
  disabled?: boolean;

  /** Dropdown children */
  children?: NavItem[];

  /** Click handler (if not using href routing) */
  onClick?: () => void;
}

export interface NavbarProps {
  /** Brand / logo area */
  brand?: React.ReactNode;

  /** Navigation items (left-aligned after brand) */
  items?: NavItem[];

  /** Items pinned to the right end */
  endItems?: React.ReactNode;

  /** Visual style. Default: 'default' */
  variant?: NavbarVariant;

  /** Background color scheme. Default: 'white' */
  color?: NavbarColor;

  /** Height preset. Default: 'md' */
  size?: NavbarSize;

  /** CSS position. Default: 'static' */
  position?: NavbarPosition;

  /** Show a bottom border. Default: true for 'default' variant */
  bordered?: boolean;

  /** Extra classes on the root <nav> */
  className?: string;

  /** Active item key (controlled) */
  activeKey?: string;

  /** Called when a nav item is clicked */
  onSelect?: (key: string) => void;
}

// ─────────────────────────────────────────────────────────────
//  NAV ITEM (recursive — supports dropdowns)
// ─────────────────────────────────────────────────────────────

function NavLink({
  item,
  activeKey,
  onSelect,
}: {
  item: NavItem;
  activeKey?: string;
  onSelect?: (key: string) => void;
}) {
  const [open, setOpen] = React.useState(false);
  const isActive   = item.active || item.key === activeKey;
  const hasDropdown = !!item.children?.length;

  function handleClick() {
    if (item.disabled) return;
    if (hasDropdown) { setOpen(o => !o); return; }
    item.onClick?.();
    onSelect?.(item.key);
  }

  return (
    <div className={['nb-item', hasDropdown ? 'nb-item-dropdown' : ''].filter(Boolean).join(' ')}>
      <button
        type="button"
        className={[
          'nb-link',
          isActive   ? 'active'   : '',
          item.disabled ? 'disabled' : '',
        ].filter(Boolean).join(' ')}
        aria-current={isActive ? 'page' : undefined}
        disabled={!!item.disabled}
        onClick={handleClick}
        aria-haspopup={hasDropdown ? 'true' : undefined}
        aria-expanded={hasDropdown ? open : undefined}
      >
        {item.icon && <span className="nb-link-icon" aria-hidden="true">{item.icon}</span>}
        {item.label}
        {item.badge !== undefined && (
          <span className="nb-badge">{item.badge}</span>
        )}
        {hasDropdown && (
          <span className={['nb-chevron', open ? 'open' : ''].filter(Boolean).join(' ')} aria-hidden="true">
            <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
              <path d="M2 3.5l3 3 3-3" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          </span>
        )}
      </button>

      {hasDropdown && open && (
        <div className="nb-dropdown">
          {item.children!.map(child => (
            <button
              key={child.key}
              type="button"
              className={[
                'nb-dropdown-item',
                child.active || child.key === activeKey ? 'active' : '',
                child.disabled ? 'disabled' : '',
              ].filter(Boolean).join(' ')}
              disabled={!!child.disabled}
              onClick={() => {
                if (child.disabled) return;
                setOpen(false);
                child.onClick?.();
                onSelect?.(child.key);
              }}
            >
              {child.icon && <span className="nb-link-icon" aria-hidden="true">{child.icon}</span>}
              {child.label}
              {child.badge !== undefined && <span className="nb-badge">{child.badge}</span>}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
//  NAVBAR
// ─────────────────────────────────────────────────────────────

function Navbar(props: NavbarProps) {
  const {
    brand,
    items       = [],
    endItems,
    variant     = 'default',
    color       = 'white',
    size        = 'md',
    position    = 'static',
    bordered,
    className   = '',
    activeKey,
    onSelect,
  } = props;

  const showBorder = bordered ?? (variant === 'default' || variant === 'bordered');

  const rootClass = [
    'nb-root',
    `nb-variant-${variant}`,
    `nb-color-${color}`,
    `nb-size-${size}`,
    `nb-pos-${position}`,
    showBorder ? 'nb-bordered' : '',
    className,
  ].filter(Boolean).join(' ');

  return (
    <nav className={rootClass} aria-label="Main navigation">
      <div className="nb-inner">
        {/* Brand */}
        {brand && <div className="nb-brand">{brand}</div>}

        {/* Main nav links */}
        {items.length > 0 && (
          <div className="nb-links" role="menubar">
            {items.map(item => (
              <NavLink key={item.key} item={item} activeKey={activeKey} onSelect={onSelect} />
            ))}
          </div>
        )}

        {/* End slot */}
        {endItems && <div className="nb-end">{endItems}</div>}
      </div>
    </nav>
  );
}

// ─────────────────────────────────────────────────────────────
//  COMPOSABLE SUB-COMPONENTS
// ─────────────────────────────────────────────────────────────

export interface NavbarRootProps {
  variant?  : NavbarVariant;
  color?    : NavbarColor;
  size?     : NavbarSize;
  position? : NavbarPosition;
  bordered? : boolean;
  className?: string;
  children  : React.ReactNode;
}

function NavbarRoot({
  variant   = 'default',
  color     = 'white',
  size      = 'md',
  position  = 'static',
  bordered,
  className = '',
  children,
}: NavbarRootProps) {
  const showBorder = bordered ?? (variant === 'default' || variant === 'bordered');
  const cls = [
    'nb-root',
    `nb-variant-${variant}`,
    `nb-color-${color}`,
    `nb-size-${size}`,
    `nb-pos-${position}`,
    showBorder ? 'nb-bordered' : '',
    className,
  ].filter(Boolean).join(' ');

  return (
    <nav className={cls} aria-label="Main navigation">
      <div className="nb-inner">{children}</div>
    </nav>
  );
}

function NavbarBrand({ children, className = '' }: { children: React.ReactNode; className?: string }) {
  return <div className={['nb-brand', className].filter(Boolean).join(' ')}>{children}</div>;
}

function NavbarLinks({ children, className = '' }: { children: React.ReactNode; className?: string }) {
  return (
    <div className={['nb-links', className].filter(Boolean).join(' ')} role="menubar">
      {children}
    </div>
  );
}

function NavbarLink({
  active,
  disabled,
  icon,
  badge,
  onClick,
  children,
  className = '',
}: {
  active?   : boolean;
  disabled? : boolean;
  icon?     : React.ReactNode;
  badge?    : string | number;
  onClick?  : () => void;
  children  : React.ReactNode;
  className?: string;
}) {
  return (
    <button
      type="button"
      className={['nb-link', active ? 'active' : '', disabled ? 'disabled' : '', className].filter(Boolean).join(' ')}
      aria-current={active ? 'page' : undefined}
      disabled={!!disabled}
      onClick={onClick}
    >
      {icon && <span className="nb-link-icon" aria-hidden="true">{icon}</span>}
      {children}
      {badge !== undefined && <span className="nb-badge">{badge}</span>}
    </button>
  );
}

function NavbarEnd({ children, className = '' }: { children: React.ReactNode; className?: string }) {
  return <div className={['nb-end', className].filter(Boolean).join(' ')}>{children}</div>;
}

// ─────────────────────────────────────────────────────────────
//  useNavbar hook
// ─────────────────────────────────────────────────────────────

export function useNavbar(initial = '') {
  const [activeKey, setActiveKey] = React.useState(initial);
  return { activeKey, onSelect: (k: string) => setActiveKey(k) };
}

export { Navbar, NavbarRoot, NavbarBrand, NavbarLinks, NavbarLink, NavbarEnd };
export default Navbar;

/* ─────────────────────────────────────────────────────────────
   NAVBAR — CSS
   Token / class-naming mirrors tabs.css & radio-group.css
   ───────────────────────────────────────────────────────────── */

:root {
  /* ── Structure ── */
  --nb-px            : 1.25rem;
  --nb-gap           : 0.25rem;

  /* ── Heights ── */
  --nb-h-xs          : 2.5rem;
  --nb-h-sm          : 3rem;
  --nb-h-md          : 3.5rem;
  --nb-h-lg          : 4rem;
  --nb-h-xl          : 4.5rem;

  /* ── Link ── */
  --nb-link-px       : 0.75rem;
  --nb-link-radius   : 0.5rem;
  --nb-link-color    : #475569;
  --nb-link-hover-bg : #f1f5f9;
  --nb-link-hover-color: #0f172a;
  --nb-link-active-color: #0f172a;
  --nb-link-fz       : 0.875rem;
  --nb-link-fw       : 500;

  /* ── Brand ── */
  --nb-brand-fz      : 1rem;
  --nb-brand-fw      : 700;
  --nb-brand-color   : #0f172a;

  /* ── Badge ── */
  --nb-badge-bg      : #e2e8f0;
  --nb-badge-color   : #475569;

  /* ── Border ── */
  --nb-border        : 1px solid #e2e8f0;

  /* ── Dropdown ── */
  --nb-dd-radius     : 0.625rem;
  --nb-dd-shadow     : 0 4px 16px rgba(15,23,42,0.10), 0 0 0 1px rgba(15,23,42,0.06);
  --nb-dd-bg         : #ffffff;

  /* ── Colors (active indicator) ── */
  --nb-color-primary  : #6366f1;
  --nb-color-secondary: #64748b;
  --nb-color-danger   : #ef4444;
  --nb-color-success  : #22c55e;
  --nb-color-warning  : #f59e0b;
  --nb-color-info     : #0ea5e9;
}

/* ══════════════════════════════════════════════════════════════
   ROOT
   ══════════════════════════════════════════════════════════════ */

.nb-root {
  width      : 100%;
  background : #ffffff;
}

.nb-bordered {
  border-bottom: var(--nb-border);
}

.nb-inner {
  display    : flex;
  align-items: center;
  height     : var(--nb-h-md);
  padding    : 0 var(--nb-px);
  gap        : 1rem;
}

/* ── Position ── */
.nb-pos-sticky { position: sticky; top: 0; z-index: 50; }
.nb-pos-fixed  { position: fixed;  top: 0; left: 0; right: 0; z-index: 50; }

/* ── Size ── */
.nb-size-xs .nb-inner { height: var(--nb-h-xs); }
.nb-size-sm .nb-inner { height: var(--nb-h-sm); }
.nb-size-md .nb-inner { height: var(--nb-h-md); }
.nb-size-lg .nb-inner { height: var(--nb-h-lg); }
.nb-size-xl .nb-inner { height: var(--nb-h-xl); }

/* ── Font sizes by size ── */
.nb-size-xs .nb-link { font-size: 0.75rem;   }
.nb-size-sm .nb-link { font-size: 0.8125rem; }
.nb-size-md .nb-link { font-size: 0.875rem;  }
.nb-size-lg .nb-link { font-size: 0.9375rem; }
.nb-size-xl .nb-link { font-size: 1rem;      }

/* ══════════════════════════════════════════════════════════════
   BRAND
   ══════════════════════════════════════════════════════════════ */

.nb-brand {
  display    : flex;
  align-items: center;
  gap        : 0.5rem;
  font-size  : var(--nb-brand-fz);
  font-weight: var(--nb-brand-fw);
  color      : var(--nb-brand-color);
  white-space: nowrap;
  flex-shrink: 0;
  text-decoration: none;
}

/* ══════════════════════════════════════════════════════════════
   NAV LINKS
   ══════════════════════════════════════════════════════════════ */

.nb-links {
  display    : flex;
  align-items: center;
  gap        : var(--nb-gap);
  flex       : 1;
}

/* Item wrapper (needed for dropdown positioning) */
.nb-item {
  position: relative;
}

/* Link button */
.nb-link {
  display        : inline-flex;
  align-items    : center;
  gap            : 0.35rem;
  height         : 2rem;
  padding        : 0 var(--nb-link-px);
  border         : none;
  border-radius  : var(--nb-link-radius);
  background     : transparent;
  color          : var(--nb-link-color);
  font-size      : var(--nb-link-fz);
  font-weight    : var(--nb-link-fw);
  white-space    : nowrap;
  cursor         : pointer;
  text-decoration: none;
  transition     : background 140ms, color 140ms;
  outline        : none;
  user-select    : none;
}

.nb-link:hover {
  background: var(--nb-link-hover-bg);
  color     : var(--nb-link-hover-color);
}

.nb-link:focus-visible {
  outline       : 2px solid var(--nb-accent, var(--nb-color-primary));
  outline-offset: 2px;
}

.nb-link.active {
  color      : var(--nb-accent, var(--nb-color-primary));
  font-weight: 600;
}

.nb-link.disabled {
  opacity       : 0.4;
  cursor        : not-allowed;
  pointer-events: none;
}

/* Icon inside link */
.nb-link-icon {
  display    : flex;
  align-items: center;
  flex-shrink: 0;
}

/* Badge inside link */
.nb-badge {
  display        : inline-flex;
  align-items    : center;
  justify-content: center;
  min-width      : 1.125rem;
  height         : 1.125rem;
  padding        : 0 0.3rem;
  border-radius  : 99px;
  font-size      : 0.6875rem;
  font-weight    : 600;
  background     : var(--nb-badge-bg);
  color          : var(--nb-badge-color);
  line-height    : 1;
}

.nb-link.active .nb-badge {
  background: var(--nb-accent, var(--nb-color-primary));
  color     : #fff;
}

/* Chevron */
.nb-chevron {
  display   : flex;
  align-items: center;
  transition: transform 200ms;
  margin-left: -0.1rem;
}
.nb-chevron.open { transform: rotate(180deg); }

/* ══════════════════════════════════════════════════════════════
   DROPDOWN
   ══════════════════════════════════════════════════════════════ */

.nb-dropdown {
  position     : absolute;
  top          : calc(100% + 0.375rem);
  left         : 0;
  min-width    : 10rem;
  background   : var(--nb-dd-bg);
  border-radius: var(--nb-dd-radius);
  box-shadow   : var(--nb-dd-shadow);
  padding      : 0.3rem;
  z-index      : 100;
  animation    : nb-dd-in 140ms ease;
}

@keyframes nb-dd-in {
  from { opacity: 0; transform: translateY(4px); }
  to   { opacity: 1; transform: translateY(0); }
}

.nb-dropdown-item {
  display        : flex;
  align-items    : center;
  gap            : 0.5rem;
  width          : 100%;
  padding        : 0.45rem 0.75rem;
  border         : none;
  border-radius  : 0.375rem;
  background     : transparent;
  color          : #334155;
  font-size      : 0.875rem;
  font-weight    : 500;
  cursor         : pointer;
  text-align     : left;
  transition     : background 120ms, color 120ms;
  white-space    : nowrap;
}

.nb-dropdown-item:hover {
  background: #f1f5f9;
  color     : #0f172a;
}

.nb-dropdown-item.active {
  color: var(--nb-accent, var(--nb-color-primary));
}

.nb-dropdown-item.disabled {
  opacity       : 0.4;
  cursor        : not-allowed;
  pointer-events: none;
}

/* ══════════════════════════════════════════════════════════════
   END SLOT
   ══════════════════════════════════════════════════════════════ */

.nb-end {
  display    : flex;
  align-items: center;
  gap        : 0.5rem;
  margin-left: auto;
  flex-shrink: 0;
}

/* ══════════════════════════════════════════════════════════════
   VARIANT: bordered
   ══════════════════════════════════════════════════════════════ */

.nb-variant-bordered {
  border-bottom: 2px solid #e2e8f0;
}

/* ══════════════════════════════════════════════════════════════
   VARIANT: filled
   ══════════════════════════════════════════════════════════════ */

.nb-variant-filled {
  background   : #f8fafc;
  border-bottom: var(--nb-border);
}

.nb-variant-filled .nb-link:hover {
  background: #e2e8f0;
}

/* ══════════════════════════════════════════════════════════════
   VARIANT: floating
   Pill-shaped bar that "floats" with a shadow ring
   ══════════════════════════════════════════════════════════════ */

.nb-variant-floating {
  background: transparent;
  border    : none;
  padding   : 0.625rem 1rem;
}

.nb-variant-floating .nb-inner {
  background   : #ffffff;
  border-radius: 9999px;
  box-shadow   : 0 0 0 1px rgba(15,23,42,0.08), 0 2px 8px rgba(15,23,42,0.08);
  padding      : 0 1rem;
}

/* ══════════════════════════════════════════════════════════════
   VARIANT: transparent
   ══════════════════════════════════════════════════════════════ */

.nb-variant-transparent {
  background: transparent;
  border    : none;
}

/* ══════════════════════════════════════════════════════════════
   COLOR: dark
   ══════════════════════════════════════════════════════════════ */

.nb-color-dark {
  background: #0f172a;
  border-color: rgba(255,255,255,0.08);
}

.nb-color-dark .nb-brand { color: #f8fafc; }

.nb-color-dark .nb-link {
  color: rgba(255,255,255,0.65);
}

.nb-color-dark .nb-link:hover {
  background: rgba(255,255,255,0.08);
  color     : #ffffff;
}

.nb-color-dark .nb-link.active {
  color: #ffffff;
  background: rgba(255,255,255,0.12);
}

.nb-color-dark .nb-badge {
  background: rgba(255,255,255,0.15);
  color     : rgba(255,255,255,0.8);
}

.nb-color-dark .nb-dropdown {
  background  : #1e293b;
  box-shadow  : 0 4px 16px rgba(0,0,0,0.35), 0 0 0 1px rgba(255,255,255,0.06);
}

.nb-color-dark .nb-dropdown-item {
  color: rgba(255,255,255,0.7);
}
.nb-color-dark .nb-dropdown-item:hover {
  background: rgba(255,255,255,0.08);
  color     : #ffffff;
}

/* ══════════════════════════════════════════════════════════════
   COLOR: primary
   ══════════════════════════════════════════════════════════════ */

.nb-color-primary {
  background  : #6366f1;
  border-color: rgba(255,255,255,0.15);
}

.nb-color-primary .nb-brand { color: #ffffff; }

.nb-color-primary .nb-link {
  color: rgba(255,255,255,0.75);
}

.nb-color-primary .nb-link:hover {
  background: rgba(255,255,255,0.15);
  color     : #ffffff;
}

.nb-color-primary .nb-link.active {
  background: rgba(255,255,255,0.2);
  color     : #ffffff;
}

.nb-color-primary .nb-badge {
  background: rgba(255,255,255,0.2);
  color     : #ffffff;
}

.nb-color-primary .nb-dropdown {
  background: #ffffff;
}

/* ══════════════════════════════════════════════════════════════
   COLOR: blur  (frosted glass — fallback to white if no backdrop)
   ══════════════════════════════════════════════════════════════ */

.nb-color-blur {
  background          : rgba(255,255,255,0.72);
  -webkit-backdrop-filter: blur(12px);
  backdrop-filter     : blur(12px);
  border-bottom       : 1px solid rgba(15,23,42,0.08);
}

/* ══════════════════════════════════════════════════════════════
   Active underline style — apply via .nb-style-underline
   ══════════════════════════════════════════════════════════════ */

.nb-style-underline .nb-link {
  border-radius: 0;
  position     : relative;
  height       : 100%;
  background   : transparent !important;
  padding-top  : 0;
  padding-bottom: 0;
}

.nb-style-underline .nb-link::after {
  content   : '';
  position  : absolute;
  bottom    : 0;
  left      : 50%;
  right     : 50%;
  height    : 2px;
  background: var(--nb-accent, var(--nb-color-primary));
  border-radius: 99px 99px 0 0;
  transition: left 180ms ease, right 180ms ease;
}

.nb-style-underline .nb-link.active::after {
  left : var(--nb-link-px);
  right: var(--nb-link-px);
}

.nb-style-underline .nb-inner {
  align-items: stretch;
}

.nb-style-underline .nb-links {
  height: 100%;
  align-items: stretch;
}

.nb-style-underline .nb-item {
  display    : flex;
  align-items: stretch;
}
